var surah031 = {
  number: 31,
  nameArabic: "Luqman",
  nameEnglish: "Luqman",
  meaning: "Luqman",
  totalAyahs: 34,
  ayahs: [
    { number: 1, arabic: "الٓمٓ", transliteration: "Aliflammeem", transliterationB: "Alif-Laaam-Meeem", english: "L. M", romanUrdu: "Alif Laam Meem" },
    { number: 2, arabic: "تِلْكَ ءَايَٰتُ ٱلْكِتَٰبِ ٱلْحَكِيمِ", transliteration: "Tilka ayatu alkitabi alhakeemi", transliterationB: "Tilka Aayaatul Kitaabil Hakeem", english: "These are Verses of the Wise Book", romanUrdu: "Yeh kitab-e-hakeem(book of wisdon) ki aayat hain" },
    { number: 3, arabic: "هُدًۭى وَرَحْمَةًۭ لِّلْمُحْسِنِينَ", transliteration: "Hudan warahmatan lilmuhsineena", transliterationB: "Hudanw wa rahmatal lilmuhsineen", english: "A Guide and a Mercy to the Doers of Good", romanUrdu: "Hidayat aur rehmat neikukar logon ke liye" },
    { number: 4, arabic: "ٱلَّذِينَ يُقِيمُونَ ٱلصَّلَوٰةَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَهُم بِٱلْءَاخِرَةِ هُمْ يُوقِنُونَ", transliteration: "Allatheena yuqeemoona alssalata wayutoona alzzakata wahum bialakhirati hum yooqinoona", transliterationB: "Allazeena yuqeemoonas Salaata wa yu'toonaz Zakaata wa hum bil Aakhirati hum yooqinoon", english: "Those who establish regular Prayer, and give regular Charity, and have (in their hearts) the assurance of the Hereafter", romanUrdu: "Jo namaz qayam karte hai, zakaat detey hain aur aakhirat par yaqeen rakhte hain" },
    { number: 5, arabic: "أُو۟لَٰٓئِكَ عَلَىٰ هُدًۭى مِّن رَّبِّهِمْ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ", transliteration: "Olaika AAala hudan min rabbihim waolaika humu almuflihoona", transliterationB: "Ulaaa'ika 'alaa hudam mir Rabbihim wa ulaaa'ika humul muflihoon", english: "These are on (true) guidance from their Lord: and these are the ones who will prosper", romanUrdu: "Yahi log apne Rubb ki taraf se raah-e-raast par hain aur yahi falaah paney waley hain" },
    { number: 6, arabic: "وَمِنَ ٱلنَّاسِ مَن يَشْتَرِى لَهْوَ ٱلْحَدِيثِ لِيُضِلَّ عَن سَبِيلِ ٱللَّهِ بِغَيْرِ عِلْمٍۢ وَيَتَّخِذَهَا هُزُوًا ۚ أُو۟لَٰٓئِكَ لَهُمْ عَذَابٌۭ مُّهِينٌۭ", transliteration: "Wamina alnnasi man yashtaree lahwa alhadeethi liyudilla AAan sabeeli Allahi bighayri AAilmin wayattakhithaha huzuwan olaika lahum AAathabun muheenun", transliterationB: "Wa minan naasi mai-yashtaree lahuwal hadeesi li yudilla 'an sabeelil laahi bighairi 'ilminw wa yattakhizahaa huzuwaa; ulaaa'ika lahum 'azaabum muheen", english: "But there are, among men, those who purchase idle tales, without knowledge (or meaning), to mislead (men) from the Path of Allah and throw ridicule (on the Path): for such there will be a Humiliating Penalty", romanUrdu: "Aur Insano hi mein se koi aisa bhi hai jo kalaam-e-dil fareb [lagv baaton ko/idle talks (i.e.music, singing, etc)] khareed kar laata hai taa-ke logon ko Allah ke raaste se ilm ke bagair bhatka dey aur is raaste ki dawat ko mazaaq mein udaday. Aise logon ke liye sakht zaleel karne wala azaab hai" },
    { number: 7, arabic: "وَإِذَا تُتْلَىٰ عَلَيْهِ ءَايَٰتُنَا وَلَّىٰ مُسْتَكْبِرًۭا كَأَن لَّمْ يَسْمَعْهَا كَأَنَّ فِىٓ أُذُنَيْهِ وَقْرًۭا ۖ فَبَشِّرْهُ بِعَذَابٍ أَلِيمٍ", transliteration: "Waitha tutla AAalayhi ayatuna walla mustakbiran kaan lam yasmaAAha kaanna fee othunayhi waqran fabashshirhu biAAathabin aleemin", transliterationB: "Wa izaa tutlaa 'alayhi Aayaatunaa wallaa mustakbiran ka al lam yasma'haa ka anna feee uzunwihi waqran fabash shiru bi'azaabin aleem", english: "When Our Signs are rehearsed to such a one, he turns away in arrogance, as if he heard them not, as if there were deafness in both his ears: announce to him a grievous Penalty", romanUrdu: "Usey jab hamari aayat sunayi jati hain to woh badey ghamand ke saath is tarah rukh pher leta hai goya ke usne unhein suna hi nahin, goya ke uske kaan behre hain.Accha mushda (tidings) suna do usey ek dardnaak azaab ka" },
    { number: 8, arabic: "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَهُمْ جَنَّٰتُ ٱلنَّعِيمِ", transliteration: "Inna allatheena amanoo waAAamiloo alssalihati lahum jannatu alnnaAAeemi", transliterationB: "Innal lazeena aamanoo wa 'amilus saalihaati lahum Janaatun Na'eem", english: "For those who believe and work righteous deeds, there will be Gardens of Bliss", romanUrdu: "Albatta jo log iman le aayein aur neik amal karein, unke liye niyamat bhari jannatein hain" },
    { number: 9, arabic: "خَٰلِدِينَ فِيهَا ۖ وَعْدَ ٱللَّهِ حَقًّۭا ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Khalideena feeha waAAda Allahi haqqan wahuwa alAAazeezu alhakeemu", transliterationB: "Khaalideena feeha wa'dal laahi haqqaa; wa Huwal 'Azeezul Hakeem", english: "To dwell therein. The promise of Allah is true: and He is Exalted in Power, Wise", romanUrdu: "Jinmein woh hamesha rahenge. Yeh Allah ka pukhta wada hai, aur woh zabardast aur hakeem hai" },
    { number: 10, arabic: "خَلَقَ ٱلسَّمَٰوَٰتِ بِغَيْرِ عَمَدٍۢ تَرَوْنَهَا ۖ وَأَلْقَىٰ فِى ٱلْأَرْضِ رَوَٰسِىَ أَن تَمِيدَ بِكُمْ وَبَثَّ فِيهَا مِن كُلِّ دَآبَّةٍۢ ۚ وَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَنۢبَتْنَا فِيهَا مِن كُلِّ زَوْجٍۢ كَرِيمٍ", transliteration: "Khalaqa alssamawati bighayri AAamadin tarawnaha waalqa fee alardi rawasiya an tameeda bikum wabaththa feeha min kulli dabbatin waanzalna mina alssamai maan faanbatna feeha min kulli zawjin kareemin", transliterationB: "Khalaqas samaawaati bi ghairi 'amadin tarawnahaa wa alqaa fil ardi rawaasiya an tameeda bikum wa bassa feehaa min kulli daaabbah; wa anzalnaa minas samaaa'i maaa'an fa ambatnaa feeha min kulli zawjin kareem", english: "He created the heavens without any pillars that ye can see; He set on the earth mountains standing firm, lest it should shake with you; and He scattered through it beasts of all kinds. We send down rain from the sky, and produce on the earth every kind of noble creature, in pairs", romanUrdu: "Usne aasmaano ko paida kiya bagair sutuno (pillars) ke jo tumko nazar aayein .Usne zameen mein pahadh jamaa diye taa-ke woh tumhein lekar dhulak (turn /shake) na jaye. Usne har tarah ke jaanwar zameen mein phayla diye aur aasmaan se pani barsaya aur zameen mein qisam qisam ke umda cheezein uga di" },
    { number: 11, arabic: "هَٰذَا خَلْقُ ٱللَّهِ فَأَرُونِى مَاذَا خَلَقَ ٱلَّذِينَ مِن دُونِهِۦ ۚ بَلِ ٱلظَّٰلِمُونَ فِى ضَلَٰلٍۢ مُّبِينٍۢ", transliteration: "Hatha khalqu Allahi faaroonee matha khalaqa allatheena min doonihi bali alththalimoona fee dalalin mubeenin", transliterationB: "Haazaa khalqul laahi fa aroonee maazaa khalaqal lazeena min doonih; baliz zaalimoona fee dalalim Mubeen", english: "Such is the Creation of Allah: now show Me what is there that others besides Him have created: nay, but the Transgressors are in manifest error", romanUrdu: "Yeh to hai Allah ki takhleeq, ab zara mujhey dikhao, in dusron ne kya paida kiya hai? Asal baat yeh hai ke yeh zaalim log sareeh gumraahi mein padey huey hain" },
    { number: 12, arabic: "وَلَقَدْ ءَاتَيْنَا لُقْمَٰنَ ٱلْحِكْمَةَ أَنِ ٱشْكُرْ لِلَّهِ ۚ وَمَن يَشْكُرْ فَإِنَّمَا يَشْكُرُ لِنَفْسِهِۦ ۖ وَمَن كَفَرَ فَإِنَّ ٱللَّهَ غَنِىٌّ حَمِيدٌۭ", transliteration: "Walaqad atayna luqmana alhikmata ani oshkur lillahi waman yashkur fainnama yashkuru linafsihi waman kafara fainna Allaha ghaniyyun hameedun", transliterationB: "Wa laqad aatainaa Luqmaanal hikmata anishkur lillaah; wa many yashkur fa innamaa yashkuru linafsihee wa man kafara fa innal laaha Ghaniyyun Hameed", english: "we bestowed (in the past) Wisdom on Luqman: \"Show (thy) gratitude to Allah.\" Any who is (so) grateful does so to the profit of his own soul: but if any is ungrateful, verily Allah is free of all wants, Worthy of all praise", romanUrdu: "Humne Luqman ko hikmat ata ki thi ke Allah ka shukar guzar ho. Jo koi shukar karey uska shukar uske apne hi liye mufeed(faiydamand) hai aur jo koi kufr karey to haqeeqat mein Allah be-niyaz aur aap se aap mehmood (Immensely Praiseworthy) hai" },
    { number: 13, arabic: "وَإِذْ قَالَ لُقْمَٰنُ لِٱبْنِهِۦ وَهُوَ يَعِظُهُۥ يَٰبُنَىَّ لَا تُشْرِكْ بِٱللَّهِ ۖ إِنَّ ٱلشِّرْكَ لَظُلْمٌ عَظِيمٌۭ", transliteration: "Waith qala luqmanu liibnihi wahuwa yaAAithuhu ya bunayya la tushrik biAllahi inna alshshirka lathulmun AAatheemun", transliterationB: "Wa iz qaala luqmaanu libnihee wa huwa ya'izuhoo ya bunaiya laa tushrik billaah; innash shirka lazulmun 'azeem", english: "Behold, Luqman said to his son by way of instruction: \"O my son! join not in worship (others) with Allah: for false worship is indeed the highest wrong-doing", romanUrdu: "Yaad karo jab Luqman apne bete ko naseehat kar raha tha to usne kaha “beta! Khuda ke saath kisi ko shareek na karna, haqq yeh hai ke shirk bahut bada zulm hai”" },
    { number: 14, arabic: "وَوَصَّيْنَا ٱلْإِنسَٰنَ بِوَٰلِدَيْهِ حَمَلَتْهُ أُمُّهُۥ وَهْنًا عَلَىٰ وَهْنٍۢ وَفِصَٰلُهُۥ فِى عَامَيْنِ أَنِ ٱشْكُرْ لِى وَلِوَٰلِدَيْكَ إِلَىَّ ٱلْمَصِيرُ", transliteration: "Wawassayna alinsana biwalidayhi hamalathu ommuhu wahnan AAala wahnin wafisaluhu fee AAamayni ani oshkur lee waliwalidayka ilayya almaseeru", transliterationB: "Wa wassainal bi waalidaihi hamalat hu ummuhoo wahnan 'alaa wahninw wa fisaaluhoo fee 'aamaini anishkur lee wa liwaalidaika ilaiyal maseer", english: "And We have enjoined on man (to be good) to his parents: in travail upon travail did his mother bear him, and in years twain was his weaning: (hear the command), \"Show gratitude to Me and to thy parents: to Me is (thy final) Goal", romanUrdu: "Aur yeh haqeeqat yeh hai ke humne Insaan ko apne walidain (parents) ka haqq pehchanne ki khud taakeed ki hai. Uski Maa ne zoaf par zoaf(weakness upon weakness) utha kar usey apne pait mein rakkha aur do saal uska doodh chootne mein lagey. (Isi liye humne usko naseehat ki ke) mera shukar kar aur apne walidain ka shukar baja la. Meri hi taraf tujhey palatna hai" },
    { number: 15, arabic: "وَإِن جَٰهَدَاكَ عَلَىٰٓ أَن تُشْرِكَ بِى مَا لَيْسَ لَكَ بِهِۦ عِلْمٌۭ فَلَا تُطِعْهُمَا ۖ وَصَاحِبْهُمَا فِى ٱلدُّنْيَا مَعْرُوفًۭا ۖ وَٱتَّبِعْ سَبِيلَ مَنْ أَنَابَ إِلَىَّ ۚ ثُمَّ إِلَىَّ مَرْجِعُكُمْ فَأُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ", transliteration: "Wain jahadaka AAala an tushrika bee ma laysa laka bihi AAilmun fala tutiAAhuma wasahibhuma fee alddunya maAAroofan waittabiAA sabeela man anaba ilayya thumma ilayya marjiAAukum faonabbiokum bima kuntum taAAmaloona", transliterationB: "Wa in jaahadaaka 'alaaa an tushrika bee maa laisa laka bihee 'ilmun falaa tuti'humaa wa saahib humaa fid dunyaa ma'roofanw wattabi' sabeela man anaaba ilayy; summa ilaiya marji'ukum fa unabbi'ukum bimaa kuntum ta'maloon", english: "But if they strive to make thee join in worship with Me things of which thou hast no knowledge, obey them not; yet bear them company in this life with justice (and consideration), and follow the way of those who turn to me (in love): in the end the return of you all is to Me, and I will tell you the truth (and meaning) of all that ye did", romanUrdu: "Lekin agar woh tujhpar dabao dalein ke mere saath tu kisi aisey ko shareek karey jisey tu nahin jaanta to unki baat hargiz na maan. Duniya mein unke saath neik bartao karta reh, magar pairvi(follow) us shaks ke raaste ki kar jisne meri taraf rujoo kiya hai. Phir tum sabko palatna meri hi taraf hai, us waqt main tumhein bata dunga ke tum kaise amal karte rahey ho" },
    { number: 16, arabic: "يَٰبُنَىَّ إِنَّهَآ إِن تَكُ مِثْقَالَ حَبَّةٍۢ مِّنْ خَرْدَلٍۢ فَتَكُن فِى صَخْرَةٍ أَوْ فِى ٱلسَّمَٰوَٰتِ أَوْ فِى ٱلْأَرْضِ يَأْتِ بِهَا ٱللَّهُ ۚ إِنَّ ٱللَّهَ لَطِيفٌ خَبِيرٌۭ", transliteration: "Ya bunayya innaha in taku mithqala habbatin min khardalin fatakun fee sakhratin aw fee alssamawati aw fee alardi yati biha Allahu inna Allaha lateefun khabeerun", transliterationB: "Ya bunaiya innahaaa in taku misqaala habbatim min khardalin fatakun fee sakhratin aw fis samaawaati aw fil ardi yaati bihal laa; innal laaha lateefun Khabeer", english: "O my son!\" (said Luqman), \"If there be (but) the weight of a mustard-seed and it were (hidden) in a rock, or (anywhere) in the heavens or on earth, Allah will bring it forth: for Allah understands the finest mysteries, (and) is well-acquainted (with them)", romanUrdu: "(Aur Luqman ne kaha tha ke) “Beta, koi cheez rai ke dana (mustard seed) barabar bhi ho aur kisi chattan (rock) mein ya aasmaano ya zameen mein kahin chupi hui ho, Allah usey nikal layega. Woh bareek been aur bakhabar hai" },
    { number: 17, arabic: "يَٰبُنَىَّ أَقِمِ ٱلصَّلَوٰةَ وَأْمُرْ بِٱلْمَعْرُوفِ وَٱنْهَ عَنِ ٱلْمُنكَرِ وَٱصْبِرْ عَلَىٰ مَآ أَصَابَكَ ۖ إِنَّ ذَٰلِكَ مِنْ عَزْمِ ٱلْأُمُورِ", transliteration: "Ya bunayya aqimi alssalata wamur bialmaAAroofi wainha AAani almunkari waisbir AAala ma asabaka inna thalika min AAazmi alomoori", transliterationB: "Yaa bunaiya aqimis-Salaata waamur bilma'roofi wanha 'anil munkari wasbir 'alaa maaa asaabaka inna zaalika min 'azmil umoor", english: "O my son! establish regular prayer, enjoin what is just, and forbid what is wrong: and bear with patient constancy whatever betide thee; for this is firmness (of purpose) in (the conduct of) affairs", romanUrdu: "Beta, namaz qayam kar, neki ka hukum de, badee (burai) se manah kar, aur jo museebat bhi padey uspar sabr kar, yeh woh baatein hain jinki badi takeed ki gayi hai" },
    { number: 18, arabic: "وَلَا تُصَعِّرْ خَدَّكَ لِلنَّاسِ وَلَا تَمْشِ فِى ٱلْأَرْضِ مَرَحًا ۖ إِنَّ ٱللَّهَ لَا يُحِبُّ كُلَّ مُخْتَالٍۢ فَخُورٍۢ", transliteration: "Wala tusaAAAAir khaddaka lilnnasi wala tamshi fee alardi marahan inna Allaha la yuhibbu kulla mukhtalin fakhoorin", transliterationB: "Wa laa tusa'-'ir khaddaka linnaasi wa laa tamshi fil ardi maarahan innal laaha laa yuhibbu kulla mukhtaalin fakhoor", english: "And swell not thy cheek (for pride) at men, nor walk in insolence through the earth; for Allah loveth not any arrogant boaster", romanUrdu: "Aur logon se mooh pher kar baat na kar, na zameen mein akad kar chal. Allah kisi khud-pasand aur faqar jataney waley shaks ko pasand nahin karta" },
    { number: 19, arabic: "وَٱقْصِدْ فِى مَشْيِكَ وَٱغْضُضْ مِن صَوْتِكَ ۚ إِنَّ أَنكَرَ ٱلْأَصْوَٰتِ لَصَوْتُ ٱلْحَمِيرِ", transliteration: "Waiqsid fee mashyika waoghdud min sawtika inna ankara alaswati lasawtu alhameeri", transliterationB: "Waqsid fee mashyika waghdud min sawtik; inna ankaral aswaati lasawtul hameer", english: "And be moderate in thy pace, and lower thy voice; for the harshest of sounds without doubt is the braying of the ass", romanUrdu: "Apni chaal mein aitadal (moderate) ikhtiyar kar, aur apni aawaz zara past rakh, sab aawazon se zyada buri aawaz gadhon ki aawaz hoti hai" },
    { number: 20, arabic: "أَلَمْ تَرَوْا۟ أَنَّ ٱللَّهَ سَخَّرَ لَكُم مَّا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ وَأَسْبَغَ عَلَيْكُمْ نِعَمَهُۥ ظَٰهِرَةًۭ وَبَاطِنَةًۭ ۗ وَمِنَ ٱلنَّاسِ مَن يُجَٰدِلُ فِى ٱللَّهِ بِغَيْرِ عِلْمٍۢ وَلَا هُدًۭى وَلَا كِتَٰبٍۢ مُّنِيرٍۢ", transliteration: "Alam taraw anna Allaha sakhkhara lakum ma fee alssamawati wama fee alardi waasbagha AAalaykum niAAamahu thahiratan wabatinatan wamina alnnasi man yujadilu fee Allahi bighayri AAilmin wala hudan wala kitabin muneerin", transliterationB: "Alam taraw annal laaha sakhkhara lakum maa fis sa maawaati wa maa fil ardi wa asbaha 'alaikum ni'amahoo zaahiratanw wa baatinah; wa minan naasi many yujaadilu fil laahi bighayri 'ilminw wa laa hudanw wa laa Kitaabim muneer", english: "Do ye not see that Allah has subjected to your (use) all things in the heavens and on earth, and has made his bounties flow to you in exceeding measure, (both) seen and unseen? Yet there are among men those who dispute about Allah, without knowledge and without guidance, and without a Book to enlighten them", romanUrdu: "Kya tumlog nahin dekhte ke Allah ne zameen aur aasmaano ki saari cheezein tumhare liye musakkhar kar rakkhi hai aur apni khuli aur chupi niyamatein tumpar tamaam kardi hain? Ispar haal yeh hai ke Insano mein se kuch log hain jo Allah ke barey mein jhagadte hain bagair iske ke unke paas koi ilm ho, ya hidayat, ya koi roshni dikhane wali kitaab" },
    { number: 21, arabic: "وَإِذَا قِيلَ لَهُمُ ٱتَّبِعُوا۟ مَآ أَنزَلَ ٱللَّهُ قَالُوا۟ بَلْ نَتَّبِعُ مَا وَجَدْنَا عَلَيْهِ ءَابَآءَنَآ ۚ أَوَلَوْ كَانَ ٱلشَّيْطَٰنُ يَدْعُوهُمْ إِلَىٰ عَذَابِ ٱلسَّعِيرِ", transliteration: "Waitha qeela lahumu ittabiAAoo ma anzala Allahu qaloo bal nattabiAAu ma wajadna AAalayhi abaana awalaw kana alshshaytanu yadAAoohum ila AAathabi alssaAAeeri", transliterationB: "Wa izaa qeela lahumut-tabi'oo maaa anzalal laahu qaaloo bal nattabi'u maa wajadnaa 'alaihi aabaaa'anaa; awalaw kaanash Shaitaanu yad'oohum ilaa 'azaabis sa'eer", english: "When they are told to follow the (Revelation) that Allah has sent down, they say: \"Nay, we shall follow the ways that we found our fathers (following). \"What! even if it is Satan beckoning them to the Penalty of the (Blazing) Fire", romanUrdu: "Aur jab unsey kaha jaata hai ke pairwi karo us cheez ki jo Allah ne nazil ki hai to kehte hain ke hum to us cheez ki pairwi karenge jispar humne apne baap dada ko paya hai. Kya yeh unhi ki pairvi karenge khwah shaytan unko bhadakti hui aag hi ki taraf kyun na bulata raha ho" },
    { number: 22, arabic: "۞ وَمَن يُسْلِمْ وَجْهَهُۥٓ إِلَى ٱللَّهِ وَهُوَ مُحْسِنٌۭ فَقَدِ ٱسْتَمْسَكَ بِٱلْعُرْوَةِ ٱلْوُثْقَىٰ ۗ وَإِلَى ٱللَّهِ عَٰقِبَةُ ٱلْأُمُورِ", transliteration: "Waman yuslim wajhahu ila Allahi wahuwa muhsinun faqadi istamsaka bialAAurwati alwuthqa waila Allahi AAaqibatu alomoori", transliterationB: "Wa many yuslim wajha hooo ilal laahi wa huwa muhsinun faqadistamsaka bil'ur watil wusqaa; wa ilal laahi 'aaqibatul umoor", english: "Whoever submits his whole self to Allah, and is a doer of good, has grasped indeed the most trustworthy hand-hold: and with Allah rests the End and Decision of (all) affairs", romanUrdu: "Jo shaks apne aap ko Allah ke hawale karde aur amalan woh neik ho, usne fil-waqayi ek bharose ke qabil sahara thaam liya, aur saarey maamlaat ka aakhri faisla Allah hi ke haath hai" },
    { number: 23, arabic: "وَمَن كَفَرَ فَلَا يَحْزُنكَ كُفْرُهُۥٓ ۚ إِلَيْنَا مَرْجِعُهُمْ فَنُنَبِّئُهُم بِمَا عَمِلُوٓا۟ ۚ إِنَّ ٱللَّهَ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ", transliteration: "Waman kafara fala yahzunka kufruhu ilayna marjiAAuhum fanunabbiohum bima AAamiloo inna Allaha AAaleemun bithati alssudoori", transliterationB: "Wa man kafara falaa yahzunka kufruh; ilainaa marji'uhum fanunabbi'uhum bimaa 'amiloo; innal laaha 'aleemum bizaatis sudoor", english: "But if any reject Faith, let not his rejection grieve thee: to Us is their return, and We shall tell them the truth of their deeds: for Allah knows well all that is in (men's) hearts", romanUrdu: "Ab jo kufr karta hai uska kufr tumhein gham mein mubtala na karey. Unhein palat kar aana to hamari hi taraf hai, phir hum unhein bata denge ke woh kya kuch karke aaye hain. Yaqeenan Allah seeno(chest) ke chupe huey raaz tak jaanta hai" },
    { number: 24, arabic: "نُمَتِّعُهُمْ قَلِيلًۭا ثُمَّ نَضْطَرُّهُمْ إِلَىٰ عَذَابٍ غَلِيظٍۢ", transliteration: "NumattiAAuhum qaleelan thumma nadtarruhum ila AAathabin ghaleethin", transliterationB: "Numatti'uhum qaleelan summa nadtarruhum ilaa 'azaabin ghaleez", english: "We grant them their pleasure for a little while: in the end shall We drive them to a chastisement unrelenting", romanUrdu: "Hum thodi muddat unhein duniya mein mazey karne ka mauqa de rahey hain, phir unko bebas karke ek sakht azaab ki taraf kheench le jayenge" },
    { number: 25, arabic: "وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ لَيَقُولُنَّ ٱللَّهُ ۚ قُلِ ٱلْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ", transliteration: "Walain saaltahum man khalaqa alssamawati waalarda layaqoolunna Allahu quli alhamdu lillahi bal aktharuhum la yaAAlamoona", transliterationB: "Wa la'in sa altahum man khalaqas samaawaati wal arda la yaqoolunnal laah; qulil hamdu lillaah; bal aksaruhum laa ya'lamoon", english: "If thou ask them, who it is that created the heavens and the earth. They will certainly say, \"Allah\". Say: \"Praise be to Allah!\" But most of them understand not", romanUrdu: "Agar tum insey pucho ke zameen aur aasmaano ko kisne paida kya hai, to yeh zaroor kahenge ke Allah ne. Kaho alhamdulillah, magar inmein se aksar log jaante nahin hain" },
    { number: 26, arabic: "لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ إِنَّ ٱللَّهَ هُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ", transliteration: "Lillahi ma fee alssamawati waalardi inna Allaha huwa alghaniyyu alhameedu", transliterationB: "Lilaahi ma fis samaa waati wal ard; innal laaha Huwal Ghaniyyul Hameed", english: "To Allah belong all things in heaven and earth: verily Allah is He (that is) free of all wants, worthy of all praise", romanUrdu: "Aasmaano aur zameen mein jo kuch hai Allah hi ka hai. Beshak Allah be-niyaz (free of need) aur aap se aap mehmood (praiseworthy) hai" },
    { number: 27, arabic: "وَلَوْ أَنَّمَا فِى ٱلْأَرْضِ مِن شَجَرَةٍ أَقْلَٰمٌۭ وَٱلْبَحْرُ يَمُدُّهُۥ مِنۢ بَعْدِهِۦ سَبْعَةُ أَبْحُرٍۢ مَّا نَفِدَتْ كَلِمَٰتُ ٱللَّهِ ۗ إِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌۭ", transliteration: "Walaw annama fee alardi min shajaratin aqlamun waalbahru yamudduhu min baAAdihi sabAAatu abhurin ma nafidat kalimatu Allahi inna Allaha AAazeezun hakeemun", transliterationB: "Wa law annamaa fil ardi min shajaratin aqlaamunw wal bahru yamudduhoo mim ba'dihee sab'atu abhurim maa nafidat Kalimaatul laah; innal laaha 'azeezun Hakeem", english: "And if all the trees on earth were pens and the ocean (were ink), with seven oceans behind it to add to its (supply), yet would not the words of Allah be exhausted (in the writing): for Allah is Exalted in Power, full of Wisdom", romanUrdu: "Zameen mein jitne darakht hain agar woh sab ke sab qalam ban jayein aur samandar (dwaat (ink) ban jaaye) jisey saat (seven) mazeed samandar roshnayi(ink) muhayya karein tab bhi Allah ki baatein (likhne se) khatam na hongi. Beshak Allah zabardast aur hakeem hai" },
    { number: 28, arabic: "مَّا خَلْقُكُمْ وَلَا بَعْثُكُمْ إِلَّا كَنَفْسٍۢ وَٰحِدَةٍ ۗ إِنَّ ٱللَّهَ سَمِيعٌۢ بَصِيرٌ", transliteration: "Ma khalqukum wala baAAthukum illa kanafsin wahidatin inna Allaha sameeAAun baseerun", transliterationB: "Maa khalqukum wa laa ba'sukum illaa kanafsinw-waa hidah; innal laaha Samee'um Baseer", english: "And your creation or your resurrection is in no wise but as an individual soul: for Allah is He Who hears and sees (all things)", romanUrdu: "Tum sarey Insano ko paida karna aur phir dobara jila uthana (zinda karna) to (uske liye) bas aisa hai jaise ek mutanaffis (single person) ko (paida karna aur jila uthana). Haqeeqat yeh hai ke Allah sabkuch sunne aur dekhne wala hai" },
    { number: 29, arabic: "أَلَمْ تَرَ أَنَّ ٱللَّهَ يُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَيُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ كُلٌّۭ يَجْرِىٓ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى وَأَنَّ ٱللَّهَ بِمَا تَعْمَلُونَ خَبِيرٌۭ", transliteration: "Alam tara anna Allaha yooliju allayla fee alnnahari wayooliju alnnahara fee allayli wasakhkhara alshshamsa waalqamara kullun yajree ila ajalin musamman waanna Allaha bima taAAmaloona khabeerun", transliterationB: "Alam tara annal laaha yoolijul laila fin nahaari wa yoolijun nahaara fil laili wa sakhkharash shamsa wal qamara kulluny yajreee ilaaa ajalim musammanw wa annal laaha bimaa ta'malona Khabeer", english: "Seest thou not that Allah merges Night into Day and he merges Day into Night; that He has subjected the sun, and the moon (to his Law), each running its course for a term appointed; and that Allah is well-acquainted with all that ye do", romanUrdu: "Kya tum dekhte nahin ho ke Allah raat ko din mein pirota hua le aata hai aur din ko raat mein? Usne Suraj aur chand ko musakkhar (subjected) kar rakkha hai. Sab ek waqt e muqarrar tak chale jaa rahey hain. Aur (kya tum nahin jantey) ke jo kuch bhi tum karte ho Allah ussey ba-kharbar hai" },
    { number: 30, arabic: "ذَٰلِكَ بِأَنَّ ٱللَّهَ هُوَ ٱلْحَقُّ وَأَنَّ مَا يَدْعُونَ مِن دُونِهِ ٱلْبَٰطِلُ وَأَنَّ ٱللَّهَ هُوَ ٱلْعَلِىُّ ٱلْكَبِيرُ", transliteration: "Thalika bianna Allaha huwa alhaqqu waanna ma yadAAoona min doonihi albatilu waanna Allaha huwa alAAaliyyu alkabeeru", transliterationB: "Zaalika bi annal laaha Huwal Haqqu wa anna maa yad'oona min doonihil baatilu wa annal laaha Huwal 'Aliyyul Kabeer", english: "That is because Allah is the (only) Reality, and because whatever else they invoke besides Him is Falsehood; and because Allah,- He is the Most High, Most Great", romanUrdu: "Yeh sabkuch is wajah se hai ke Allah hi haqq hai aur usey chodh kar jin dusri cheezon ko yeh log pukarte hain woh sab baatil hain.Aur (is wajah se ke) Allah hi buzurg o bartar hai" },
    { number: 31, arabic: "أَلَمْ تَرَ أَنَّ ٱلْفُلْكَ تَجْرِى فِى ٱلْبَحْرِ بِنِعْمَتِ ٱللَّهِ لِيُرِيَكُم مِّنْ ءَايَٰتِهِۦٓ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّكُلِّ صَبَّارٍۢ شَكُورٍۢ", transliteration: "Alam tara anna alfulka tajree fee albahri biniAAmati Allahi liyuriyakum min ayatihi inna fee thalika laayatin likulli sabbarin shakoorin", transliterationB: "Alam tara annal fulka tajree fil bahri bini'matil laahi li yuriyakum min Aayaatih; inna fee zaalika la Aayaatil likulli sabbaarin shakoor", english: "Seest thou not that the ships sail through the ocean by the Grace of Allah?- that He may show you of His Signs? Verily in this are Signs for all who constantly persevere and give thanks", romanUrdu: "Kya tum dekhte nahin ho ke kashti samandar mein Allah ke fazal se chalti hai taa-ke woh tumhein apni kuch nishaniyan dikhaye? Dar haqeeqat is mein bahut si nishaniyan hain har us shaks ke liye jo sabr aur shukar karne wala ho" },
    { number: 32, arabic: "وَإِذَا غَشِيَهُم مَّوْجٌۭ كَٱلظُّلَلِ دَعَوُا۟ ٱللَّهَ مُخْلِصِينَ لَهُ ٱلدِّينَ فَلَمَّا نَجَّىٰهُمْ إِلَى ٱلْبَرِّ فَمِنْهُم مُّقْتَصِدٌۭ ۚ وَمَا يَجْحَدُ بِـَٔايَٰتِنَآ إِلَّا كُلُّ خَتَّارٍۢ كَفُورٍۢ", transliteration: "Waitha ghashiyahum mawjun kaalththulali daAAawoo Allaha mukhliseena lahu alddeena falamma najjahum ila albarri faminhum muqtasidun wama yajhadu biayatina illa kullu khattarin kafoorin", transliterationB: "Wa izaa ghashiyahum mawjun kazzulali da'a-wul laaha mukhliseena lahud deena fa lammaa najjaahum ilal barri faminhum muqtasid; wa maa yajhadu bi Aayaatinaa illaa kullu khattaarin kafoor", english: "When a wave covers them like the canopy (of clouds), they call to Allah, offering Him sincere devotion. But when He has delivered them safely to land, there are among them those that halt between (right and wrong). But none reject Our Signs except only a perfidious ungrateful (wretch)", romanUrdu: "Aur jab (samandar mein ) in logon par ek mauj saayebaano(like canopies) ki tarah chaaa jaati hai to yeh Allah ko pukarte hain apne deen ko bilkul usi ke liye khaalis karke. Phir jab woh bacha kar inhein khushki (land) tak pahuncha deta hai to inmein se koi iqtesad baratta (lukewarm) hai.Aur hamari nishaniyon ka inkar nahin karta magar har woh shaks jo gaddaar aur nashukra hai" },
    { number: 33, arabic: "يَٰٓأَيُّهَا ٱلنَّاسُ ٱتَّقُوا۟ رَبَّكُمْ وَٱخْشَوْا۟ يَوْمًۭا لَّا يَجْزِى وَالِدٌ عَن وَلَدِهِۦ وَلَا مَوْلُودٌ هُوَ جَازٍ عَن وَالِدِهِۦ شَيْـًٔا ۚ إِنَّ وَعْدَ ٱللَّهِ حَقٌّۭ ۖ فَلَا تَغُرَّنَّكُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا وَلَا يَغُرَّنَّكُم بِٱللَّهِ ٱلْغَرُورُ", transliteration: "Ya ayyuha alnnasu ittaqoo rabbakum waikhshaw yawman la yajzee walidun AAan waladihi wala mawloodun huwa jazin AAan walidihi shayan inna waAAda Allahi haqqun fala taghurrannakumu alhayatu alddunya wala yaghurrannakum biAllahi algharooru", transliterationB: "Yaaa ayyuhan naasuttaqoo Rabbakum wakhshaw Yawmal laa yajzee waalidun 'anw waladihee wa laa mawloodun huwa jaazin 'anw waalidihee shai'aa; innaa wa'dal laahi haqqun falaa taghurran nakumul hayaatud dunyaa wa laa yaghur rannakum billaahil gharoon", english: "O mankind! do your duty to your Lord, and fear (the coming of) a Day when no father can avail aught for his son, nor a son avail aught for his father. Verily, the promise of Allah is true: let not then this present life deceive you, nor let the chief Deceiver deceive you about Allah", romanUrdu: "Logon, bacho apne Rubb ke gazab se aur daro us din se jabke koi baap apne bete ki taraf se badla na dega aur na koi beta hi apne baap ki taraf se kuch badla dene wala hoga. Filwaqeh Allah ka wada sachha hai. Pas yeh duniya ki zindagi tumhein dhoke mein na daale, aur na dhoke-baaz tumko Allah ke maamle mein dhoka dene paye" },
    { number: 34, arabic: "إِنَّ ٱللَّهَ عِندَهُۥ عِلْمُ ٱلسَّاعَةِ وَيُنَزِّلُ ٱلْغَيْثَ وَيَعْلَمُ مَا فِى ٱلْأَرْحَامِ ۖ وَمَا تَدْرِى نَفْسٌۭ مَّاذَا تَكْسِبُ غَدًۭا ۖ وَمَا تَدْرِى نَفْسٌۢ بِأَىِّ أَرْضٍۢ تَمُوتُ ۚ إِنَّ ٱللَّهَ عَلِيمٌ خَبِيرٌۢ", transliteration: "Inna Allaha AAindahu AAilmu alssaAAati wayunazzilu alghaytha wayaAAlamu ma fee alarhami wama tadree nafsun matha taksibu ghadan wama tadree nafsun biayyi ardin tamootu inna Allaha AAaleemun khabeerun", transliterationB: "Innal laaha 'indahoo 'ilmus saa'ati wa yunazzilul ghaisa wa ya'lamu maa fil arhaami wa maa tadree nafsum maazaa takisbu ghadaa; wa maa tadree nafsum bi ayyi ardin tamoot; innal laaha 'Aleemun Khabeer", english: "Verily the knowledge of the Hour is with Allah (alone). It is He Who sends down rain, and He Who knows what is in the wombs. Nor does any one know what it is that he will earn on the morrow: Nor does any one know in what land he is to die. Verily with Allah is full knowledge and He is acquainted (with all things)", romanUrdu: "Us ghadi ka ilm Allah hi ke paas hai, wahi baarish barsata hai, wahi jaanta hai ke maaon ke paithon mein kya parwarish paa raha hai, koi mutanaffis nahin jaanta ke kal woh kya kamayi karne wala hai aur na kisi shaks ko yeh khabar hai ke kis sar-zameen mein usko maut aani hai. Allah hi sabkuch jaanney wala aur bakhabar hai" }
  ]
};
